module master_slave_d_latch(  
    input D,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
    reg obf_master;  
    always @(posedge CLK) begin  
        obf_master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= obf_master;  
        Qn <= ~obf_master;  
    end  
endmodule
